import java.util.*;
class Solution {
  public int[] intersection(int[] a, int[] b) {
    Set<Integer> set = new HashSet<>(), ans = new HashSet<>();
    for (int x : a) set.add(x);
    for (int x : b) if (set.contains(x)) ans.add(x);
    int[] res = new int[ans.size()]; int i = 0;
    for (int x : ans) res[i++] = x;
    return res;
  }
}
