class Solution {
  public ListNode removeElements(ListNode head, int val) {
    ListNode dummy = new ListNode(0, head), cur = dummy;
    while (cur.next != null) {
      if (cur.next.val == val) cur.next = cur.next.next;
      else cur = cur.next;
    }
    return dummy.next;
  }
}
