class Solution {
  public int kthSmallest(TreeNode root, int k) {
    Deque<TreeNode> st = new ArrayDeque<>();
    while (root != null || !st.isEmpty()) {
      while (root != null) { st.push(root); root = root.left; }
      root = st.pop(); if (--k == 0) return root.val; root = root.right;
    }
