import java.util.*;
class Solution {
  public int orangesRotting(int[][] grid) {
    Queue<int[]> q = new ArrayDeque<>(); int fresh = 0, time = 0;
    for (int i=0;i<grid.length;i++) for(int j=0;j<grid[0].length;j++){ if(grid[i][j]==2) q.offer(new int[]{i,j}); if(grid[i][j]==1) fresh++; }
    int[][] d={{1,0},{-1,0},{0,1},{0,-1}};
    while(fresh>0&&!q.isEmpty()){ for(int s=q.size();s>0;s--){ int[] p=q.poll(); for(int[] e:d){int x=p[0]+e[0],y=p[1]+e[1]; if(x>=0&&y>=0&&x<grid.length&&y<grid[0].length&&grid[x][y]==1){grid[x][y]=2;fresh--;q.offer(new int[]{x,y});}}} time++; }
    return fresh==0?time:-1;
  }
}
