class Solution {
  public List<Integer> spiralOrder(int[][] m) {
    List<Integer> ans = new ArrayList<>(); int top=0,bot=m.length-1,l=0,r=m[0].length-1;
    while(top<=bot&&l<=r){ for(int j=l;j<=r;j++)ans.add(m[top][j]); top++; for(int i=top;i<=bot;i++)ans.add(m[i][r]); r--; if(top<=bot){for(int j=r;j>=l;j--)ans.add(m[bot][j]); bot--;} if(l<=r){for(int i=bot;i>=top;i--)ans.add(m[i][l]); l++;}}
    return ans;
  }
}
