import java.util.*;
class Solution {
  public String decodeString(String s) {
    Deque<Integer> nums = new ArrayDeque<>(); Deque<StringBuilder> strs = new ArrayDeque<>();
    StringBuilder cur = new StringBuilder(); int k = 0;
    for (char c : s.toCharArray()) {
      if (Character.isDigit(c)) k = k * 10 + c - '0';
      else if (c == '[') { nums.push(k); strs.push(cur); k = 0; cur = new StringBuilder(); }
      else if (c == ']') { int n = nums.pop(); StringBuilder prev = strs.pop(); while (n-- > 0) prev.append(cur); cur = prev; }
      else cur.append(c);
    }
    return cur.toString();
  }
}
