  private void dfs(String s,int start,List<String> path,List<List<String>> ans){ if(start==s.length()){ans.add(new ArrayList<>(path));return;} for(int end=start;end<s.length();end++) if(isPal(s,start,end)){path.add(s.substring(start,end+1));dfs(s,end+1,path,ans);path.remove(path.size()-1);} }
  private boolean isPal(String s,int l,int r){while(l<r)if(s.charAt(l++)!=s.charAt(r--))return false;return true;}
