class Solution {
  public String longestPalindrome(String s) {
    int start = 0, len = 0;
    for (int i = 0; i < s.length(); i++) {
      int a = expand(s,i,i), b = expand(s,i,i+1), cur = Math.max(a,b);
      if (cur > len) { len = cur; start = i - (cur - 1) / 2; }
    }
