    for (int i = 0; i < n; i++) {
      int mask = 1 << i;
      queue.offer(new int[] {i, mask, 0});
      seen[i][mask] = true;
    }
    while (!queue.isEmpty()) {
      int[] cur = queue.poll();
      int node = cur[0], mask = cur[1], dist = cur[2];
      if (mask == target) return dist;
      for (int next : graph[node]) {
        int nextMask = mask | (1 << next);
        if (!seen[next][nextMask]) {
          seen[next][nextMask] = true;
          queue.offer(new int[] {next, nextMask, dist + 1});
        }
      }
    }
    return 0;
  }
}
