import java.util.*;

class Solution {
  public String minWindow(String s1, String s2) {
    int bestStart = -1, bestLen = Integer.MAX_VALUE;
    int i = 0, n = s1.length(), m = s2.length();
    while (i < n) {
      int j = 0;
      while (i < n) {
        if (s1.charAt(i) == s2.charAt(j) && ++j == m) break;
        i++;
      }
      if (i == n) break;
      int end = i + 1;
      j = m - 1;
      while (i >= 0) {
        if (s1.charAt(i) == s2.charAt(j) && --j < 0) break;
        i--;
      }
      if (end - i < bestLen) {
        bestLen = end - i;
        bestStart = i;
      }
      i++;
    }
    return bestStart == -1 ? "" : s1.substring(bestStart, bestStart + bestLen);
  }
}
