import java.util.*;

class Solution {
  private PriorityQueue<Integer> small = new PriorityQueue<>((a, b) -> Integer.compare(b, a));
  private PriorityQueue<Integer> large = new PriorityQueue<>();
  private Map<Integer, Integer> delayed = new HashMap<>();
  private int smallSize = 0, largeSize = 0;

  public double[] medianSlidingWindow(int[] nums, int k) {
    double[] ans = new double[nums.length - k + 1];
    for (int i = 0; i < nums.length; i++) {
      add(nums[i]);
      if (i >= k) remove(nums[i - k]);
      if (i >= k - 1) ans[i - k + 1] = median(k);
    }
    return ans;
  }

  private void add(int num) {
    if (small.isEmpty() || num <= small.peek()) { small.offer(num); smallSize++; }
    else { large.offer(num); largeSize++; }
    balance();
  }

  private void remove(int num) {
    delayed.put(num, delayed.getOrDefault(num, 0) + 1);
    if (num <= small.peek()) smallSize--; else largeSize--;
    prune(small); prune(large); balance();
  }

  private void balance() {
    if (smallSize > largeSize + 1) { large.offer(small.poll()); smallSize--; largeSize++; prune(small); }
    if (smallSize < largeSize) { small.offer(large.poll()); largeSize--; smallSize++; prune(large); }
  }

  private void prune(PriorityQueue<Integer> heap) {
    while (!heap.isEmpty() && delayed.getOrDefault(heap.peek(), 0) > 0) {
      int x = heap.poll();
      delayed.put(x, delayed.get(x) - 1);
    }
  }

  private double median(int k) {
    return (k & 1) == 1 ? small.peek() : ((long) small.peek() + large.peek()) / 2.0;
  }
}
```
