import java.util.*;

class Solution {
  public List<List<String>> accountsMerge(List<List<String>> accounts) {
    Map<String, String> parent = new HashMap<>();
    Map<String, String> owner = new HashMap<>();
    for (List<String> account : accounts) {
      String name = account.get(0);
      for (int i = 1; i < account.size(); i++) {
        parent.putIfAbsent(account.get(i), account.get(i));
        owner.put(account.get(i), name);
        union(parent, account.get(1), account.get(i));
      }
    }
    Map<String, TreeSet<String>> groups = new HashMap<>();
    for (String email : parent.keySet()) {
      groups.computeIfAbsent(find(parent, email), k -> new TreeSet<>()).add(email);
    }
    List<List<String>> ans = new ArrayList<>();
    for (TreeSet<String> emails : groups.values()) {
      List<String> merged = new ArrayList<>();
      merged.add(owner.get(emails.first()));
      merged.addAll(emails);
      ans.add(merged);
    }
    return ans;
  }

  private String find(Map<String, String> parent, String x) {
    if (!parent.get(x).equals(x)) parent.put(x, find(parent, parent.get(x)));
    return parent.get(x);
  }

  private void union(Map<String, String> parent, String a, String b) {
    parent.put(find(parent, a), find(parent, b));
  }
}
