import java.util.*;

class Solution {
  static class TrieNode {
    TrieNode[] next = new TrieNode[26];
    String word;
  }

  public List<String> findWords(char[][] board, String[] words) {
    TrieNode root = buildTrie(words);
    List<String> ans = new ArrayList<>();
    for (int i = 0; i < board.length; i++) {
      for (int j = 0; j < board[0].length; j++) dfs(board, i, j, root, ans);
    }
    return ans;
  }

  private void dfs(char[][] board, int i, int j, TrieNode node, List<String> ans) {
    if (i < 0 || i == board.length || j < 0 || j == board[0].length || board[i][j] == '#') return;
    char c = board[i][j];
    TrieNode next = node.next[c - 'a'];
    if (next == null) return;
    if (next.word != null) {
      ans.add(next.word);
      next.word = null;
    }
    board[i][j] = '#';
    dfs(board, i + 1, j, next, ans);
    dfs(board, i - 1, j, next, ans);
    dfs(board, i, j + 1, next, ans);
    dfs(board, i, j - 1, next, ans);
    board[i][j] = c;
  }

  private TrieNode buildTrie(String[] words) {
    TrieNode root = new TrieNode();
    for (String word : words) {
      TrieNode cur = root;
      for (char c : word.toCharArray()) {
        int idx = c - 'a';
        if (cur.next[idx] == null) cur.next[idx] = new TrieNode();
        cur = cur.next[idx];
      }
      cur.word = word;
    }
    return root;
  }
}
