import java.util.*;

class LFUCache {
  private final int capacity;
  private int minFreq = 0;
  private final Map<Integer, Integer> values = new HashMap<>();
  private final Map<Integer, Integer> freqs = new HashMap<>();
  private final Map<Integer, LinkedHashSet<Integer>> buckets = new HashMap<>();

  public LFUCache(int capacity) {
    this.capacity = capacity;
  }

  public int get(int key) {
    if (!values.containsKey(key)) return -1;
    touch(key);
    return values.get(key);
  }

  public void put(int key, int value) {
    if (capacity == 0) return;
    if (values.containsKey(key)) {
      values.put(key, value);
      touch(key);
      return;
    }
    if (values.size() == capacity) {
      int evict = buckets.get(minFreq).iterator().next();
      buckets.get(minFreq).remove(evict);
      values.remove(evict);
      freqs.remove(evict);
    }
    values.put(key, value);
    freqs.put(key, 1);
    buckets.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
    minFreq = 1;
  }

  private void touch(int key) {
    int freq = freqs.get(key);
    buckets.get(freq).remove(key);
    if (freq == minFreq && buckets.get(freq).isEmpty()) minFreq++;
    freqs.put(key, freq + 1);
    buckets.computeIfAbsent(freq + 1, k -> new LinkedHashSet<>()).add(key);
  }
}
```
